mapper.select:


    b.del_flag = '0'

        AND b.batch_name like '%' || #{batchName} || '%'


        AND b.batch_status = #{batchStatus}


        AND b.responsible_unit_name like '%' || #{responsibleUnitName} || '%'


        AND b.dept_id = #{deptId}


        AND b.responsible_unit_id = #{responsibleUnitId}


        AND b.region_code = #{regionCode}


        AND b.period_key = #{periodKey}

    ${params.dataScope}

order by b.create_time desc, b.batch_id desc

mapper.update:
update nc_fusion_collection_batch
batch_status = #{batchStatus}, audit_by = #{auditBy}, audit_time = #{auditTime}, audit_opinion = #{auditOpinion}, update_by = #{updateBy}, update_time = #{updateTime},
where batch_id = #{batchId} and del_flag = '0' and batch_status = #{expectedStatus}

update nc_fusion_collection_batch
set item_count = #{itemCount}, update_by = #{updateBy}, update_time = #{updateTime}
where batch_id = #{batchId}

mapper.select:
select count(1)
from nc_fusion_collection_item i
inner join nc_fusion_collection_batch b on b.batch_id = i.batch_id
where i.del_flag = '0'
  and b.del_flag = '0'
  and b.batch_status != 'rejected'
  and i.indicator_id = #{indicatorId}
  and i.responsible_unit_id = #{responsibleUnitId}
  and i.period_key = #{periodKey}


          and i.region_code = #{regionCode}


          and (i.region_code is null or i.region_code = '')

select count(1)
from sys_dept d
where d.del_flag = '0'
  and d.dept_id = #{deptId}
${params.dataScope}

select f.failure_id, f.dept_id, f.import_batch_name, f.source_record_id, f.row_num,
       f.field_name, f.raw_value, f.failure_reason, f.create_by, f.create_time, f.remark
from nc_fusion_collection_import_failure f


        AND f.dept_id = #{deptId}


        AND f.import_batch_name like '%' || #{importBatchName} || '%'


        AND f.source_record_id = #{sourceRecordId}

    ${params.dataScope}

order by f.create_time desc, f.failure_id desc
